"""管理员命令模块"""
import discord
from discord.ext import commands
from bot.config import settings


def is_admin():
    """检查是否为管理员"""
    async def predicate(ctx):
        return ctx.author.id in settings.ADMIN_IDS or ctx.author.guild_permissions.administrator
    return commands.check(predicate)


class Admin(commands.Cog):
    """管理员命令"""

    def __init__(self, bot):
        self.bot = bot

    @commands.command(name="reload")
    @is_admin()
    async def reload_cog(self, ctx, cog_name: str):
        """重载指定 Cog"""
        try:
            await self.bot.reload_extension(f"bot.cogs.{cog_name}")
            await ctx.send(f"已重载 {cog_name}")
        except Exception as e:
            await ctx.send(f"重载失败: {e}")

    @commands.command(name="sync")
    @is_admin()
    async def sync_commands(self, ctx):
        """同步斜杠命令"""
        synced = await self.bot.tree.sync()
        await ctx.send(f"已同步 {len(synced)} 个命令")

"""通用工具函数"""
import discord


def create_embed(title: str, description: str, color: discord.Color = None) -> discord.Embed:
    """创建嵌入式消息"""
    return discord.Embed(
        title=title,
        description=description,
        color=color or discord.Color.blue()
    )


def format_duration(seconds: int) -> str:
    """格式化时长"""
    minutes, seconds = divmod(seconds, 60)
    hours, minutes = divmod(minutes, 60)

    if hours:
        return f"{hours}:{minutes:02d}:{seconds:02d}"
    return f"{minutes}:{seconds:02d}"
